#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');

const projectRoot = path.resolve(__dirname, '..');
const entryFile = path.resolve(projectRoot, 'src/main.js');
const outputFile = path.resolve(projectRoot, 'game.bundle.js');

const importRegex = /^\s*import\s+(?:[^"']+?\s+from\s+)?["'](.+?)["']\s*;?\s*$/gm;

function readFileSafe(filePath) {
  try {
    return fs.readFileSync(filePath, 'utf8');
  } catch (error) {
    throw new Error(`Failed to read file: ${path.relative(projectRoot, filePath)}\n${error.message}`);
  }
}

function resolveImport(importerPath, specifier) {
  if (!specifier.startsWith('.')) {
    throw new Error(
      `Unsupported import specifier "${specifier}" in ${path.relative(projectRoot, importerPath)}. ` +
      'Only local relative imports are supported.'
    );
  }

  const basePath = path.resolve(path.dirname(importerPath), specifier);
  const candidates = [basePath, `${basePath}.js`, path.join(basePath, 'index.js')];
  for (const candidate of candidates) {
    if (fs.existsSync(candidate) && fs.statSync(candidate).isFile()) {
      return candidate;
    }
  }

  throw new Error(
    `Could not resolve import "${specifier}" in ${path.relative(projectRoot, importerPath)}.`
  );
}

function stripModuleSyntax(code) {
  return code
    .replace(/^\s*import\s+(?:[^"']+?\s+from\s+)?["'][^"']+["']\s*;?\s*$/gm, '')
    .replace(/^\s*export\s+default\s+/gm, '')
    .replace(/^\s*export\s+(?=(const|let|var|function|class)\b)/gm, '');
}

function bundleFromEntry(entryPath) {
  const visiting = new Set();
  const visited = new Set();
  const ordered = [];

  function visit(filePath) {
    if (visited.has(filePath)) return;
    if (visiting.has(filePath)) {
      throw new Error(`Circular import detected around ${path.relative(projectRoot, filePath)}.`);
    }

    visiting.add(filePath);
    const source = readFileSafe(filePath);

    importRegex.lastIndex = 0;
    const imports = [];
    let match;
    while ((match = importRegex.exec(source)) !== null) {
      imports.push(match[1]);
    }

    for (const specifier of imports) {
      const dependencyPath = resolveImport(filePath, specifier);
      visit(dependencyPath);
    }

    visiting.delete(filePath);
    visited.add(filePath);
    ordered.push(filePath);
  }

  visit(entryPath);

  const chunks = ordered.map((filePath) => {
    const relativePath = path.relative(projectRoot, filePath).replace(/\\/g, '/');
    const source = readFileSafe(filePath);
    const transformed = stripModuleSyntax(source).trim();
    return `// ---- ${relativePath} ----\n${transformed}\n`;
  });

  return `/* Auto-generated by tools/build-dev-bundle.js. Do not edit game.bundle.js directly. */\n\n${chunks.join('\n')}`;
}

function main() {
  try {
    const bundled = bundleFromEntry(entryFile);
    if (/^\s*import\s/m.test(bundled) || /^\s*export\s/m.test(bundled)) {
      throw new Error('Bundle contains unresolved import/export syntax.');
    }
    fs.writeFileSync(outputFile, bundled, 'utf8');
    console.log(`Built ${path.relative(projectRoot, outputFile)} from ${path.relative(projectRoot, entryFile)}.`);
  } catch (error) {
    console.error('[build-dev-bundle] Build failed.');
    console.error(error instanceof Error ? error.message : String(error));
    process.exitCode = 1;
  }
}

main();
